pub mod status {
    use arkon_core::{config::{ArkonConfig, TargetConfig}, error::Result};
    use std::{net::TcpStream, path::Path, time::Duration};
    use serde::Serialize;

    #[derive(Serialize)]
    struct TargetStatus {
        name:   String,
        kind:   String,
        online: bool,
        host:   Option<String>,
        url:    Option<String>,
        latency_ms: Option<u64>,
    }

    pub async fn run(root: &Path, target: Option<&str>) -> Result<()> {
        let (config, _) = ArkonConfig::load(root)?;

        let statuses: Vec<TargetStatus> = config.targets.iter()
            .filter(|(k, _)| target.map(|t| k.as_str() == t).unwrap_or(true))
            .map(|(name, cfg)| probe_target(name, cfg))
            .collect();

        if crate::json_output::is_enabled() {
            let json = serde_json::to_string_pretty(&statuses)
                .unwrap_or_else(|_| "[]".into());
            println!("{json}");
            return Ok(());
        }

        println!();
        for s in &statuses {
            let dot = if s.online { "\x1b[32mÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â\x1b[0m" } else { "\x1b[31mÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â\x1b[0m" };
            let lat = s.latency_ms.map(|ms| format!("  \x1b[2m{ms}ms\x1b[0m")).unwrap_or_default();
            let host = s.host.as_deref().unwrap_or("");
            println!("  {dot}  \x1b[1m{:16}\x1b[0m  \x1b[2m{:8}\x1b[0m  {}{lat}",
                s.name, s.kind, host);
        }
        println!();

        let offline: usize = statuses.iter().filter(|s| !s.online).count();
        if offline > 0 {
            crate::print::warn(&format!("{offline} target(s) unreachable"));
        } else {
            crate::print::success("all targets reachable");
        }
        println!();
        Ok(())
    }

    fn probe_target(name: &str, cfg: &TargetConfig) -> TargetStatus {
        match cfg {
            TargetConfig::Ssh(c) => {
                let host  = format!("{}:{}", c.host, c.port.unwrap_or(22));
                let start = std::time::Instant::now();
                let ok    = TcpStream::connect_timeout(
                    &host.parse().unwrap_or_else(|_| "0.0.0.0:0".parse().unwrap()),
                    Duration::from_secs(4),
                ).is_ok();
                let ms = start.elapsed().as_millis() as u64;
                TargetStatus {
                    name: name.to_string(), kind: "ssh".into(), online: ok,
                    host: Some(c.host.clone()), url: None,
                    latency_ms: if ok { Some(ms) } else { None },
                }
            }
            TargetConfig::S3(c) => {
                // TCP probe to port 443 of the endpoint host ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â avoids reqwest::blocking
                let host = c.endpoint.as_deref()
                    .and_then(|ep| url::Url::parse(ep).ok())
                    .and_then(|u| u.host_str().map(|h| h.to_string()))
                    .unwrap_or_else(|| format!(
                        "s3.{}.amazonaws.com",
                        c.region.as_deref().unwrap_or("us-east-1")
                    ));
                let addr = format!("{host}:443");
                let start = std::time::Instant::now();
                let ok    = TcpStream::connect_timeout(
                    &addr.parse().unwrap_or_else(|_| "0.0.0.0:443".parse().unwrap()),
                    Duration::from_secs(4),
                ).is_ok();
                let ms = start.elapsed().as_millis() as u64;
                TargetStatus {
                    name: name.to_string(), kind: "s3".into(), online: ok,
                    host: Some(host), url: None,
                    latency_ms: if ok { Some(ms) } else { None },
                }
            }
            TargetConfig::Webrtc(_) => TargetStatus {
                name: name.to_string(), kind: "webrtc".into(), online: true,
                host: None, url: None, latency_ms: None,
            },
            TargetConfig::Ipfs(c) => {
                let api = c.api.clone().unwrap_or_else(|| "http://127.0.0.1:5001".into());
                let ok  = TcpStream::connect_timeout(
                    &"127.0.0.1:5001".parse().unwrap(),
                    Duration::from_secs(2),
                ).is_ok();
                TargetStatus {
                    name: name.to_string(), kind: "ipfs".into(), online: ok,
                    host: Some(api), url: None, latency_ms: None,
                }
            }
            TargetConfig::GithubPages(c) => TargetStatus {
                name: name.to_string(), kind: "github-pages".into(), online: true,
                host: Some(c.repo.clone()), url: None, latency_ms: None,
            },
            _ => TargetStatus {
                name: name.to_string(), kind: "local".into(), online: true,
                host: None, url: None, latency_ms: None,
            },
        }
    }
}

