pub mod preview {
    use arkon_adapters::{AdapterRegistry, BuildCtx, BuildRunner};
    use arkon_core::{config::ArkonConfig, error::Result};
    use arkon_detector::detect;
    use arkon_p2p;
    use arkon_secrets::Vault;
    use std::path::Path;

    pub async fn run(root: &Path, ttl: &str) -> Result<()> {
        // 1. Load config + detect project
        let (config, config_path) = ArkonConfig::load(root)?;
        let project_root = config_path.parent().unwrap_or(root).to_path_buf();

        let detection = detect(&project_root)?;
        detection.print_summary();

        let adapter_name = config.project.adapter.as_deref()
            .unwrap_or(&detection.adapter);

        // 2. Build the artifact
        let registry = AdapterRegistry::default();
        let adapter  = registry.get(adapter_name)?;
        let vault    = Vault::open(&config.project.name)?;
        let env_map  = vault.export_all()
            .map(|m| m.into_iter().map(|(k,v)| (k, v.to_string())).collect::<std::collections::HashMap<String,String>>())
            .unwrap_or_default();

        let ctx = BuildCtx {
            root: project_root.clone(),
            env:  env_map,
            command_override:    config.build.command.clone(),
            output_dir_override: config.build.output_dir.clone(),
            cache_enabled:       config.project.cache,
            last_fingerprint:    String::new(),
        };

        crate::print::info(&format!("building for preview (adapter: {})", adapter.name()));
        let runner   = BuildRunner { adapter: adapter.as_ref(), ctx: &ctx };
        let artifact = runner.run()?;

        // 3. Start P2P session
        crate::print::info("starting P2P preview tunnel...");
        let session = arkon_p2p::start_preview(
            &artifact.path,
            &config.project.name,
            ttl,
        ).await?;

        if crate::json_output::is_enabled() {
            let out = crate::json_output::JsonResult {
                ok:       true,
                version:  env!("CARGO_PKG_VERSION").to_string(),
                command:  "preview".to_string(),
                project:  config.project.name.clone(),
                adapter:  adapter.name().to_string(),
                url:      Some(session.public_url.clone()),
                peer_id:  Some(session.peer_id.clone()),
                ttl_secs: Some(session.ttl_secs),
                artifact_fingerprint: artifact.fingerprint.clone(),
                size_bytes: Some(artifact.size_bytes),
                ..Default::default()
            };
            crate::json_output::output_success(&out);
        } else {
            crate::print::separator();
            println!();
            println!(
                "  \x1b[32mÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â\x1b[0m  \x1b[1mPreview live\x1b[0m  (expires in {})",
                session.ttl_display()
            );
            crate::print::url("share link", &session.public_url);
            crate::print::url("local url",  &session.local_url);
            println!();
            crate::print::info("press Ctrl+C to stop");
            println!();
        }

        // 4. Wait for Ctrl+C or TTL
        tokio::select! {
            _ = tokio::signal::ctrl_c() => {
                crate::print::info("stopping preview...");
            }
            _ = session.wait_for_expiry() => {
                crate::print::info("preview TTL elapsed");
            }
        }
        Ok(())
    }
}

