pub mod serve {
    use arkon_core::{config::ArkonConfig, error::Result};
    use arkon_daemon::{AuditLog, HealthMonitor};
    use arkon_adapters::AdapterRegistry;
    use std::path::Path;

    pub async fn run(root: &Path) -> Result<()> {
        let (config, _) = ArkonConfig::load(root)?;

        crate::print::info("starting ARKON daemon");
        crate::print::step("project",  &config.project.name);
        crate::print::step("monitors", &config.health.len().to_string());
        println!();

        // 1. Start health monitor for all configured targets
        if !config.health.is_empty() {
            let monitor = HealthMonitor::new(config.health.clone());
            tokio::spawn(async move {
                monitor.run().await;
            });
            crate::print::success(&format!(
                "health monitor started ({} target(s))",
                config.health.len()
            ));
        }

        // 2. Community adapter hot-reload watcher
        let adapter_dir = dirs::home_dir()
            .unwrap_or_default()
            .join(".arkon")
            .join("adapters");

        if adapter_dir.exists() {
            let registry = AdapterRegistry::default();
            let dir = adapter_dir.clone();
            tokio::spawn(async move {
                loop {
                    tokio::time::sleep(tokio::time::Duration::from_secs(10)).await;
                    let _ = registry.load_community_dir(&dir);
                }
            });
            crate::print::success("adapter hot-reload watcher started");
        }

        crate::print::info("press Ctrl+C to stop daemon");
        println!();

        // 3. Block until signal
        tokio::signal::ctrl_c().await.ok();
        crate::print::info("daemon stopped");
        Ok(())
    }
}

// end of mod_impl

