pub mod cost {
    use arkon_adapters::{AdapterRegistry, BuildCtx, BuildRunner};
    use arkon_core::{config::ArkonConfig, error::Result};
    use arkon_detector::detect;
    use arkon_secrets::Vault;
    use arkon_targets::Dispatcher;
    use std::path::Path;

    pub async fn run(root: &Path, target: Option<&str>) -> Result<()> {
        let (config, config_path) = ArkonConfig::load(root)?;
        let project_root = config_path.parent().unwrap_or(root).to_path_buf();

        let detection    = detect(&project_root)?;
        let adapter_name = config.project.adapter.as_deref().unwrap_or(&detection.adapter);

        let registry = AdapterRegistry::default();
        let adapter  = registry.get(adapter_name)?;
        let vault    = Vault::open(&config.project.name)?;
        let env      = vault.export_all()
            .map(|m| m.into_iter().map(|(k,v)| (k, v.to_string())).collect::<std::collections::HashMap<String,String>>())
            .unwrap_or_default();

        let ctx = BuildCtx {
            root: project_root.clone(),
            env,
            command_override:    config.build.command.clone(),
            output_dir_override: config.build.output_dir.clone(),
            cache_enabled:       true,
            last_fingerprint:    String::new(),
        };

        crate::print::info("building artifact for cost estimate (no deploy)...");
        let runner   = BuildRunner { adapter: adapter.as_ref(), ctx: &ctx };
        let artifact = runner.run()?;

        let target_names: Vec<String> = if let Some(t) = target {
            vec![t.to_string()]
        } else {
            config.targets.keys().cloned().collect()
        };

        let dispatcher = Dispatcher::default();
        let mut rows: Vec<serde_json::Value> = Vec::new();

        println!();
        crate::print::info(&format!(
            "artifact: \x1b[1m{:.1}MB\x1b[0m  fingerprint: \x1b[2m{}\x1b[0m",
            artifact.size_bytes as f64 / 1_048_576.0,
            &artifact.fingerprint[..12],
        ));
        println!();

        for name in &target_names {
            let cfg = match config.target(name) {
                Ok(c) => c,
                Err(_) => continue,
            };
            let target_impl = dispatcher.target_for(cfg);
            let hint = target_impl
                .and_then(|t| t.cost_estimate(&artifact, cfg))
                .unwrap_or_else(arkon_core::runtime::CostHint::free);

            rows.push(serde_json::json!({
                "target":               name,
                "upload_usd":           hint.upload_usd,
                "egress_monthly_usd":   hint.egress_monthly_usd,
                "total_usd":            hint.total(),
                "breakdown":            hint.breakdown,
            }));

            if !crate::json_output::is_enabled() {
                println!(
                    "  \x1b[1m{:16}\x1b[0m  upload \x1b[33m${:.4}\x1b[0m  \
                     egress/mo \x1b[33m${:.4}\x1b[0m  \x1b[2m{}\x1b[0m",
                    name, hint.upload_usd, hint.egress_monthly_usd, hint.breakdown
                );
            }
        }

        if crate::json_output::is_enabled() {
            println!("{}", serde_json::to_string_pretty(&rows).unwrap_or_default());
        } else {
            println!();
            crate::print::info("run \x1b[1markon ship\x1b[0m to deploy");
            println!();
        }
        Ok(())
    }
}
